#!/bin/bash NETWORK="172.16.1.0/24" OUTPUT="hosts.txt" PORTS=(13 37 30000 3000) echo "[+] Descobrindo hosts ativos..." nmap -sn -n $NETWORK -oG - | awk '/Up$/{print $2}' > $OUTPUT echo echo "[+] Hosts encontrados:" cat $OUTPUT echo for TARGET in $(cat $OUTPUT); do echo "[*] Executando port knocking em $TARGET" # Knock sequence for port in "${PORTS[@]}"; do timeout 1 bash -c "echo > /dev/tcp/$TARGET/$port" 2>/dev/null sleep 0.2 done # Verifica se abriu a 1337 timeout 1 bash -c "echo > /dev/tcp/$TARGET/1337" 2>/dev/null if [ $? -eq 0 ]; then echo echo "[!!!] HOST INFECTADO ENCONTRADO: $TARGET" echo "[!!!] Porta 1337 aberta!" echo else echo "[-] 1337 fechada em $TARGET" fi done
